"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[777],{64641:e=>{e.exports=JSON.parse('{"functions":[{"name":"SegmentSize","desc":"Starting sub-segment length in studs. Smaller values produce more raycasts\\nper frame and better thin-surface detection at the cost of performance.\\nAdjusted adaptively at runtime.\\n\\nDefault: `0.5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":294,"path":"docs/SubBuilders.lua"}},{"name":"FrameBudget","desc":"Target wall-clock budget in milliseconds this cast may spend on sub-segment\\nraycasts per frame. The adaptive system scales segment size up or down to\\nstay near this target.\\n\\nDefault: `4`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":306,"path":"docs/SubBuilders.lua"}},{"name":"AdaptiveScale","desc":"Multiplier applied when coarsening or refining segment size adaptively.\\nMust be `> 1`. Higher values adapt faster but with less precision.\\n\\nDefault: `1.5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":317,"path":"docs/SubBuilders.lua"}},{"name":"MinSegmentSize","desc":"Hard floor for adaptive segment size reduction in studs.\\nMust be `<= SegmentSize`. Prevents the adaptive algorithm from shrinking\\nsegments to near-zero.\\n\\nDefault: `0.1`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":329,"path":"docs/SubBuilders.lua"}},{"name":"MaxBouncesPerFrame","desc":"Maximum bounces allowed across all sub-segments within a single frame step.\\nPrevents a bullet from exhausting its entire lifetime bounce budget in one frame.\\n\\nDefault: `10`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":340,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":347,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"HighFidelityBuilder","desc":"Sub-builder for high-fidelity raycasting configuration. Opened via\\n[BehaviorBuilder:HighFidelity]. Call `:Done()` to return to the root [BehaviorBuilder].\\n\\nHigh-fidelity mode subdivides each frame\'s travel into multiple smaller raycasts\\nto prevent fast bullets from tunnelling through thin surfaces. The segment size\\nis adjusted adaptively each frame to stay near the configured frame budget.","source":{"line":282,"path":"docs/SubBuilders.lua"}}')}}]);